t.script:
(function(){
  var sidebarOpen = window.innerWidth > 768;
  var notifOpen = false;
  var refreshSec = 30;
  var remaining = refreshSec;

  // Init sidebar on mobile
  if(window.innerWidth <= 768){
    var sb = document.getElementById('vp-sidebar');
    if(sb) sb.style.transform = 'translateX(-100%)';
  }

  window.vpToggleSidebar = function(){
    var sb = document.getElementById('vp-sidebar');
    var main = document.getElementById('vp-main');
    var h1 = document.getElementById('vph1');
    var h2 = document.getElementById('vph2');
    var h3 = document.getElementById('vph3');
    sidebarOpen = !sidebarOpen;
    if(sidebarOpen){
      sb.style.transform = '';
      if(window.innerWidth > 768) main.style.marginLeft = '220px';
      if(h1){ h1.style.transform=''; h2.style.opacity='1'; h3.style.transform=''; }
    } else {
      sb.style.transform = 'translateX(-100%)';
      if(window.innerWidth > 768) main.style.marginLeft = '0';
      if(h1){ h1.style.transform='rotate(45deg) translate(4px,4px)'; h2.style.opacity='0'; h3.style.transform='rotate(-45deg) translate(4px,-4px)'; }
    }
  };

  window.vpToggleNotif = function(){
    notifOpen = !notifOpen;
    var panel = document.getElementById('vp-notif-panel');
    if(panel) panel.classList.toggle('open', notifOpen);
  };

  window.vpClearNotif = function(){
    document.querySelectorAll('.vp-notif-item.unread').forEach(function(i){ i.classList.remove('unread'); });
    var dot = document.getElementById('vp-notif-dot');
    var badge = document.getElementById('vp-notif-badge');
    if(dot) dot.classList.remove('show');
    if(badge) badge.style.display = 'none';
  };

  document.addEventListener('click', function(e){
    if(notifOpen && !e.target.closest('#vp-notif-panel') && !e.target.closest('.vp-notif-btn')){
      notifOpen = false;
      var panel = document.getElementById('vp-notif-panel');
      if(panel) panel.classList.remove('open');
    }
  });

  // Refresh countdown
  setInterval(function(){
    remaining--;
    var el = document.getElementById('vp-refresh-sec');
    if(el) el.textContent = remaining;
    if(remaining <= 0){
      remaining = refreshSec;
      // Poll for new orders
      vpCheckNotifications();
    }
  }, 1000);

  // Poll notifications
  window.vpCheckNotifications = function(){
    fetch('/my/vendor/notifications/poll', {
      method: 'GET',
      headers: {'X-Requested-With': 'XMLHttpRequest'}
    })
    .then(function(r){ return r.json(); })
    .then(function(data){
      if(data.count > 0){
        var dot = document.getElementById('vp-notif-dot');
        var badge = document.getElementById('vp-notif-badge');
        var list = document.getElementById('vp-notif-list');
        if(dot) dot.classList.add('show');
        if(badge){ badge.textContent = data.count; badge.style.display = 'inline'; }
        if(list && data.items){
          list.innerHTML = '';
          data.items.forEach(function(item){
            var div = document.createElement('div');
            div.className = 'vp-notif-item' + (item.unread ? ' unread' : '');
            div.innerHTML =
              '<div class="vp-ni-icon" style="background:' + item.bg + ';color:' + item.color + '"><i class="fa ' + item.icon + '"></i></div>' +
              '<div class="vp-ni-text"><strong>' + item.title + '</strong><span>' + item.body + '</span></div>' +
              '<span class="vp-ni-time">' + item.time + '</span>';
            list.appendChild(div);
          });
        }
      }
    })
    .catch(function(){});
  };

  // Initial poll after 3s
  setTimeout(window.vpCheckNotifications, 3000);
})();

(function(){
  // Flash sale timer (2hr countdown demo)
  var end = new Date().getTime() + 2*3600*1000;
  function tick(){
    var now = new Date().getTime();
    var diff = Math.max(0, end - now);
    var h = Math.floor(diff/3600000);
    var m = Math.floor((diff%3600000)/60000);
    var s = Math.floor((diff%60000)/1000);
    var pad = function(n){ return n < 10 ? '0'+n : n; };
    var hEl = document.getElementById('vs-h');
    var mEl = document.getElementById('vs-m');
    var sEl = document.getElementById('vs-s');
    if(hEl) hEl.textContent = pad(h);
    if(mEl) mEl.textContent = pad(m);
    if(sEl) sEl.textContent = pad(s);
  }
  tick();
  setInterval(tick, 1000);

  // Follow button
  var btn = document.getElementById('vs-follow-btn');
  if(btn){
    btn.addEventListener('click', function(){
      var slug = btn.dataset.slug;
      fetch('/store/'+slug+'/follow', {
        method:'POST',
        headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'},
        body: JSON.stringify({jsonrpc:'2.0',method:'call',params:{}})
      }).then(function(r){ return r.json(); }).then(function(data){
        if(data.result){
          var f = data.result.following;
          btn.dataset.following = f ? '1' : '0';
          btn.innerHTML = f
            ? ' Following'
            : ' Follow';
        }
      });
    });
  }
})();
